# riscv64 boot stub - generated by Sage

.section .text
.global _start
_start:

	# Disable machine interrupts (clear mstatus.MIE)
	csrci mstatus, 0x8

	# Set stack pointer
	la sp, stack_top

	# Zero BSS section
	la t0, __bss_start
	la t1, __bss_end
.Lbss_zero:
	bge t0, t1, .Lbss_done
	sd zero, 0(t0)
	addi t0, t0, 8
	j .Lbss_zero
.Lbss_done:

	# Jump to entry point
	call kmain

.Lhalt_riscv64:
	wfi
	j .Lhalt_riscv64

.section .bss
.align 16
stack_bottom:
	.skip 16384
stack_top:

.section .text
.global serial_init, serial_putchar, serial_puts
serial_init:
    li t0, 0x10000000
    # Disable interrupts
    sb zero, 1(t0)
    # Enable DLAB
    li t1, 0x80
    sb t1, 3(t0)
    # Divisor = 1 (115200 baud at 1.8432MHz)
    li t1, 1
    sb t1, 0(t0)
    sb zero, 1(t0)
    # 8N1
    li t1, 3
    sb t1, 3(t0)
    # Enable FIFO
    li t1, 0xC7
    sb t1, 2(t0)
    # DTR + RTS + OUT2
    li t1, 0x0B
    sb t1, 4(t0)
    ret

serial_putchar:
    li t0, 0x10000000
.Lwait_tx:
    lb t1, 5(t0)
    andi t1, t1, 0x20
    beqz t1, .Lwait_tx
    sb a0, 0(t0)
    ret

serial_puts:
    addi sp, sp, -16
    sd ra, 8(sp)
    sd s0, 0(sp)
    mv s0, a0
.Lputs_loop:
    lb a0, 0(s0)
    beqz a0, .Lputs_done
    call serial_putchar
    addi s0, s0, 1
    j .Lputs_loop
.Lputs_done:
    ld ra, 8(sp)
    ld s0, 0(sp)
    addi sp, sp, 16
    ret

